import fetch from 'node-fetch';

async function run() {
  const eventKey = 'YOUR_eventKey_PARAMETER';
  const response = await fetch(`https://frc.nexus/api/v1/event/${eventKey}`, {
    method: 'GET',
    headers: {
      'Nexus-Api-Key': 'YOUR_API_KEY_HERE',
    },
  });

  if (!response.ok) {
    const errorMessage = await response.text();
    console.error('Error getting live event status:', errorMessage);
    return;
  }

  const data = await response.json();
  console.log('Successfully got live event status', data);

  // Get information about a specific team's next match.
  const myTeamNumber = '100';
  const myMatches = data.matches.filter(m => m.redTeams?.includes(myTeamNumber) || m.blueTeams?.includes(myTeamNumber));
  const myNextMatch = myMatches.find(m => m.status !== 'On field');

  if (myNextMatch) {
    console.log(`Team ${myTeamNumber}'s next match is ${myNextMatch.label} (${myNextMatch.status})!`);

    const allianceColor = myNextMatch.redTeams?.includes(myTeamNumber) ? 'red' : 'blue';
    console.log(`Put on the ${allianceColor} bumpers`);

    const estimatedQueueTime = myNextMatch.times.estimatedQueueTime;
    if (estimatedQueueTime) {
      console.log(`We will be queued at ~${new Date(estimatedQueueTime).toLocaleTimeString()}`);
    }
  } else {
    console.log(`Team ${myTeamNumber} doesn't have any future matches scheduled yet`);
  }

  // Get announcements and parts requests.
  data.announcements.forEach(announcement => console.log(`Event announcement: ${announcement.announcement}`));
  data.partsRequests.forEach(partsRequest =>
    console.log(`Parts request for team ${partsRequest.requestedByTeam}: ${partsRequest.parts}`),
  );
}

run();

import java.net.*;
import java.net.http.*;
import java.util.*;

public class App {
  public static void main(String[] args) throws Exception {
    var httpClient = HttpClient.newBuilder().build();

    var host = "https://frc.nexus";
    var eventKey = "YOUR_eventKey_PARAMETER";
    var path = "/api/v1/event/" + eventKey;
    var request = HttpRequest.newBuilder()
      .GET()
      .uri(URI.create(host + path))
      .header("Nexus-Api-Key", "YOUR_API_KEY_HERE")
      .build();

    var response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

    System.out.println(response.body());
  }
}
